import pytest


def test_happy_path_single_level():
    """Test getting value from single level dictionary."""
    d = {"a": 1, "b": 2, "c": 3}
    assert deep_get(d, "a") == 1
    assert deep_get(d, "b") == 2
    assert deep_get(d, "c") == 3


def test_happy_path_nested():
    """Test getting value from nested dictionaries."""
    d = {"a": {"b": {"c": 42}}}
    assert deep_get(d, "a.b.c") == 42
    assert deep_get(d, "a.b") == {"c": 42}
    assert deep_get(d, "a") == {"b": {"c": 42}}


def test_happy_path_mixed_nesting():
    """Test getting value from dictionaries with mixed nesting levels."""
    d = {
        "user": {
            "name": "Alice",
            "address": {
                "street": "123 Main St",
                "city": "Boston"
            }
        },
        "settings": {"theme": "dark"}
    }

    assert deep_get(d, "user.name") == "Alice"
    assert deep_get(d, "user.address.city") == "Boston"
    assert deep_get(d, "settings.theme") == "dark"
    assert deep_get(d, "user.address") == {"street": "123 Main St", "city": "Boston"}


def test_default_value_when_key_not_found():
    """Test that default value is returned when key doesn't exist."""
    d = {"a": 1, "b": 2}

    # Single level
    assert deep_get(d, "c") is None
    assert deep_get(d, "c", default="not found") == "not found"

    # Nested - intermediate key doesn't exist
    assert deep_get(d, "a.b.c") is None
    assert deep_get(d, "a.b.c", default=0) == 0

    # Custom default value
    assert deep_get(d, "x.y.z", default="N/A") == "N/A"


def test_default_value_when_nested_key_not_found():
    """Test default value with nested dictionaries."""
    d = {"a": {"b": 1}}

    assert deep_get(d, "a.c") is None
    assert deep_get(d, "a.c.d") is None
    assert deep_get(d, "a.c.d", default=[]) == []


def test_empty_keys_string():
    """Test behavior with empty keys string."""
    d = {"a": 1}

    # Empty keys string should return the entire dictionary
    assert deep_get(d, "") == d
    assert deep_get(d, "", default="default") == d


def test_none_dictionary():
    """Test behavior when dictionary is None."""
    assert deep_get(None, "a.b.c") is None
    assert deep_get(None, "a.b.c", default="default") == "default"


def test_non_dict_intermediate_value():
    """Test when intermediate value is not a dictionary."""
    d = {"a": {"b": 42}}

    # b is not a dict, so trying to access b.c should return default
    assert deep_get(d, "a.b.c") is None
    assert deep_get(d, "a.b.c", default="not a dict") == "not a dict"

    # Another example
    d2 = {"list": [1, 2, 3]}
    assert deep_get(d2, "list.0") is None  # list is not a dict
    assert deep_get(d2, "list.length", default=0) == 0


def test_keys_with_multiple_dots():
    """Test keys string with multiple consecutive dots."""
    d = {"a": {"b": 1}}

    # Multiple dots create empty keys
    assert deep_get(d, "a..b") is None
    assert deep_get(d, "a...b", default="default") == "default"
    assert deep_get(d, ".a.b") is None
    assert deep_get(d, "a.b.") is None


